COPY supabase_migrations.schema_migrations (version, statements, name) FROM stdin;
001	{"-- WebriQ Central Hub — Phase 1 Schema\n-- Migration 001: Initial tables\n-- Order: customers first (referenced by all others)\n\ncreate extension if not exists \\"pgcrypto\\"","-- ─── customers ────────────────────────────────────────────────────────────────\ncreate table if not exists customers (\n  id              uuid primary key default gen_random_uuid(),\n  customer_id     text unique not null,\n  company_name    text not null,\n  contact_name    text,\n  contact_email   text,\n  zoho_account_id text,\n  status          text not null default 'active' check (status in ('active', 'inactive', 'onboarding')),\n  created_at      timestamptz not null default now(),\n  updated_at      timestamptz not null default now()\n)","create index if not exists idx_customers_customer_id on customers (customer_id)","create index if not exists idx_customers_status on customers (status)","-- ─── customer_products ────────────────────────────────────────────────────────\ncreate table if not exists customer_products (\n  id                  uuid primary key default gen_random_uuid(),\n  customer_id         text not null references customers (customer_id) on delete cascade,\n  product_name        text not null check (product_name in ('StackShift', 'PublishForge', 'CiteForge', 'PipelineForge')),\n  product_instance_id text,\n  sanity_project_id   text,\n  zoho_project_id     text,\n  github_repo         text,\n  status              text not null default 'active' check (status in ('active', 'inactive')),\n  onboarding_complete boolean not null default false,\n  onboarding_data     jsonb not null default '{}',\n  created_at          timestamptz not null default now(),\n  updated_at          timestamptz not null default now()\n)","create index if not exists idx_customer_products_customer_id on customer_products (customer_id)","create index if not exists idx_customer_products_product_name on customer_products (product_name)","-- ─── classification_records ───────────────────────────────────────────────────\ncreate table if not exists classification_records (\n  id               uuid primary key default gen_random_uuid(),\n  customer_id      text not null references customers (customer_id) on delete cascade,\n  zoho_ticket_id   text,\n  zoho_task_id     text,\n  source           text not null check (source in ('zoho_desk', 'zoho_projects')),\n  title            text not null,\n  description      text,\n  task_type        text,\n  priority         text check (priority in ('low', 'medium', 'high', 'critical')),\n  llm_eligible     boolean not null default false,\n  confidence_score numeric(5, 2),\n  model_used       text,\n  input_tokens     integer,\n  output_tokens    integer,\n  raw_response     jsonb,\n  status           text not null default 'pending' check (status in ('pending', 'reviewed', 'rejected')),\n  reviewed_by      text,\n  reviewed_at      timestamptz,\n  created_at       timestamptz not null default now()\n)","create index if not exists idx_classification_records_customer_id on classification_records (customer_id)","create index if not exists idx_classification_records_status on classification_records (status)","create index if not exists idx_classification_records_created_at on classification_records (created_at desc)","-- ─── requirements_assessments ─────────────────────────────────────────────────\ncreate table if not exists requirements_assessments (\n  id                    uuid primary key default gen_random_uuid(),\n  classification_id     uuid not null references classification_records (id) on delete cascade,\n  customer_id           text not null references customers (customer_id) on delete cascade,\n  subtasks              jsonb not null default '[]',\n  overall_status        text not null check (overall_status in ('CLEAR', 'PARTIAL', 'BLOCKED')),\n  clarification_draft   text,\n  model_used            text,\n  input_tokens          integer,\n  output_tokens         integer,\n  assessment_version    integer not null default 1,\n  created_at            timestamptz not null default now()\n)","create index if not exists idx_requirements_assessments_classification_id on requirements_assessments (classification_id)","create index if not exists idx_requirements_assessments_customer_id on requirements_assessments (customer_id)","-- ─── implementation_plans ─────────────────────────────────────────────────────\ncreate table if not exists implementation_plans (\n  id               uuid primary key default gen_random_uuid(),\n  assessment_id    uuid not null references requirements_assessments (id) on delete cascade,\n  customer_id      text not null references customers (customer_id) on delete cascade,\n  steps            jsonb not null default '[]',\n  affected_files   jsonb not null default '[]',\n  apis_involved    jsonb not null default '[]',\n  playbooks_used   jsonb not null default '[]',\n  confidence_score numeric(5, 2),\n  risk_flags       jsonb not null default '[]',\n  status           text not null default 'draft'\n    check (status in ('draft', 'approved', 'rejected', 'executing', 'complete', 'failed')),\n  rejection_reason text\n    check (rejection_reason in ('PLAN_INCOMPLETE', 'WRONG_APPROACH', 'SCOPE_EXCEEDED', 'KNOWLEDGE_GAP', 'MISCLASSIFICATION')),\n  rejected_by      text,\n  approved_by      text,\n  model_used       text,\n  input_tokens     integer,\n  output_tokens    integer,\n  created_at       timestamptz not null default now(),\n  updated_at       timestamptz not null default now()\n)","create index if not exists idx_implementation_plans_assessment_id on implementation_plans (assessment_id)","create index if not exists idx_implementation_plans_customer_id on implementation_plans (customer_id)","create index if not exists idx_implementation_plans_status on implementation_plans (status)","-- ─── execution_records ────────────────────────────────────────────────────────\ncreate table if not exists execution_records (\n  id                  uuid primary key default gen_random_uuid(),\n  plan_id             uuid not null references implementation_plans (id) on delete cascade,\n  customer_id         text not null references customers (customer_id) on delete cascade,\n  status              text not null default 'pending'\n    check (status in ('pending', 'running', 'complete', 'failed', 'partial', 'reverted')),\n  pre_action_states   jsonb not null default '{}',\n  post_action_states  jsonb not null default '{}',\n  github_pr_url       text,\n  preview_url         text,\n  error_message       text,\n  failure_count       integer not null default 0,\n  started_at          timestamptz,\n  completed_at        timestamptz,\n  created_at          timestamptz not null default now()\n)","create index if not exists idx_execution_records_plan_id on execution_records (plan_id)","create index if not exists idx_execution_records_customer_id on execution_records (customer_id)","create index if not exists idx_execution_records_status on execution_records (status)","-- ─── playbooks ────────────────────────────────────────────────────────────────\ncreate table if not exists playbooks (\n  id          uuid primary key default gen_random_uuid(),\n  customer_id text references customers (customer_id) on delete cascade,\n  task_type   text not null,\n  title       text not null,\n  content     text not null,\n  version     integer not null default 1,\n  is_active   boolean not null default true,\n  source      text not null default 'manual' check (source in ('manual', 'generated', 'learned')),\n  created_at  timestamptz not null default now(),\n  updated_at  timestamptz not null default now()\n)","create index if not exists idx_playbooks_task_type on playbooks (task_type)","create index if not exists idx_playbooks_customer_id on playbooks (customer_id)","create index if not exists idx_playbooks_is_active on playbooks (is_active)","-- ─── llm_invocation_logs ──────────────────────────────────────────────────────\ncreate table if not exists llm_invocation_logs (\n  id                  uuid primary key default gen_random_uuid(),\n  customer_id         text,\n  orchestration_layer text not null\n    check (orchestration_layer in ('classification', 'assessment', 'planning', 'execution', 'digest', 'reply', 'wiki_lint')),\n  model_used          text not null,\n  input_tokens        integer not null default 0,\n  output_tokens       integer not null default 0,\n  cost_usd            numeric(10, 6),\n  duration_ms         integer,\n  status              text not null default 'success' check (status in ('success', 'error', 'timeout')),\n  error_message       text,\n  reference_id        uuid,\n  reference_type      text,\n  created_at          timestamptz not null default now()\n)","create index if not exists idx_llm_invocation_logs_customer_id on llm_invocation_logs (customer_id)","create index if not exists idx_llm_invocation_logs_orchestration_layer on llm_invocation_logs (orchestration_layer)","create index if not exists idx_llm_invocation_logs_created_at on llm_invocation_logs (created_at desc)","-- ─── digest_logs ──────────────────────────────────────────────────────────────\ncreate table if not exists digest_logs (\n  id            uuid primary key default gen_random_uuid(),\n  digest_type   text not null check (digest_type in ('pm', 'dev')),\n  target_user   text,\n  content       jsonb not null,\n  model_used    text,\n  input_tokens  integer,\n  output_tokens integer,\n  feedback      text check (feedback in ('useful', 'partial', 'not_useful')),\n  feedback_at   timestamptz,\n  digest_date   date not null,\n  created_at    timestamptz not null default now()\n)","create index if not exists idx_digest_logs_digest_type on digest_logs (digest_type)","create index if not exists idx_digest_logs_digest_date on digest_logs (digest_date desc)","-- ─── llm_config ───────────────────────────────────────────────────────────────\ncreate table if not exists llm_config (\n  id                  uuid primary key default gen_random_uuid(),\n  orchestration_layer text unique not null\n    check (orchestration_layer in ('classification', 'assessment', 'planning', 'execution', 'digest', 'reply', 'wiki_lint')),\n  model_id            text not null,\n  max_tokens          integer not null default 4096,\n  temperature         numeric(3, 2) not null default 0.3,\n  system_prompt_key   text,\n  is_active           boolean not null default true,\n  notes               text,\n  updated_at          timestamptz not null default now()\n)","-- ─── updated_at trigger ───────────────────────────────────────────────────────\ncreate or replace function update_updated_at_column()\nreturns trigger language plpgsql as $$\nbegin\n  new.updated_at = now();\n  return new;\nend;\n$$","create trigger set_updated_at_customers\n  before update on customers\n  for each row execute function update_updated_at_column()","create trigger set_updated_at_customer_products\n  before update on customer_products\n  for each row execute function update_updated_at_column()","create trigger set_updated_at_implementation_plans\n  before update on implementation_plans\n  for each row execute function update_updated_at_column()","create trigger set_updated_at_playbooks\n  before update on playbooks\n  for each row execute function update_updated_at_column()","create trigger set_updated_at_llm_config\n  before update on llm_config\n  for each row execute function update_updated_at_column()"}	initial_schema
002	{"-- WebriQ Central Hub — LLM Config Seed\n-- Migration 002: Seed llm_config with Haiku/Sonnet assignments per orchestration layer\n\ninsert into llm_config (orchestration_layer, model_id, max_tokens, temperature, notes)\nvalues\n  ('classification', 'claude-haiku-4-5-20251001', 1024,  0.10, 'Haiku: fast, cost-efficient classification of every incoming task/ticket'),\n  ('assessment',     'claude-sonnet-4-6',         4096,  0.30, 'Sonnet: requirements breakdown with CLEAR/PARTIAL/BLOCKED subtask analysis'),\n  ('planning',       'claude-sonnet-4-6',         8192,  0.30, 'Sonnet: multi-step implementation plan with confidence score and risk flags'),\n  ('execution',      'claude-sonnet-4-6',         8192,  0.20, 'Sonnet: tool-use execution via Sanity API / GitHub PR creation'),\n  ('digest',         'claude-haiku-4-5-20251001', 2048,  0.40, 'Haiku: daily PM and Dev digest pre-compiled by cron — stored, not live'),\n  ('reply',          'claude-haiku-4-5-20251001', 1024,  0.50, 'Haiku: customer reply draft on task completion — PM reviews before send'),\n  ('wiki_lint',      'claude-haiku-4-5-20251001', 2048,  0.20, 'Haiku: weekly KB audit for contradictions, stale references, orphan pages')\non conflict (orchestration_layer) do update set\n  model_id    = excluded.model_id,\n  max_tokens  = excluded.max_tokens,\n  temperature = excluded.temperature,\n  notes       = excluded.notes,\n  updated_at  = now()"}	seed_llm_config
003	{"-- WebriQ Central Hub — Row Level Security\n-- Migration 003: Enable RLS on all tables with permissive authenticated policies\n-- Phase 2 will add per-customer policies once the user/customer mapping is defined.\n\n-- Enable RLS\nalter table customers              enable row level security","alter table customer_products      enable row level security","alter table classification_records enable row level security","alter table requirements_assessments enable row level security","alter table implementation_plans   enable row level security","alter table execution_records      enable row level security","alter table playbooks              enable row level security","alter table llm_invocation_logs    enable row level security","alter table digest_logs            enable row level security","alter table llm_config             enable row level security","-- ─── Permissive policies for authenticated users (Phase 1 — tighten in Phase 2) ──\n\ncreate policy \\"authenticated_read_customers\\"\n  on customers for select to authenticated using (true)","create policy \\"authenticated_write_customers\\"\n  on customers for all to authenticated using (true) with check (true)","create policy \\"authenticated_read_customer_products\\"\n  on customer_products for select to authenticated using (true)","create policy \\"authenticated_write_customer_products\\"\n  on customer_products for all to authenticated using (true) with check (true)","create policy \\"authenticated_read_classification_records\\"\n  on classification_records for select to authenticated using (true)","create policy \\"authenticated_write_classification_records\\"\n  on classification_records for all to authenticated using (true) with check (true)","create policy \\"authenticated_read_requirements_assessments\\"\n  on requirements_assessments for select to authenticated using (true)","create policy \\"authenticated_write_requirements_assessments\\"\n  on requirements_assessments for all to authenticated using (true) with check (true)","create policy \\"authenticated_read_implementation_plans\\"\n  on implementation_plans for select to authenticated using (true)","create policy \\"authenticated_write_implementation_plans\\"\n  on implementation_plans for all to authenticated using (true) with check (true)","create policy \\"authenticated_read_execution_records\\"\n  on execution_records for select to authenticated using (true)","create policy \\"authenticated_write_execution_records\\"\n  on execution_records for all to authenticated using (true) with check (true)","create policy \\"authenticated_read_playbooks\\"\n  on playbooks for select to authenticated using (true)","create policy \\"authenticated_write_playbooks\\"\n  on playbooks for all to authenticated using (true) with check (true)","create policy \\"authenticated_read_llm_invocation_logs\\"\n  on llm_invocation_logs for select to authenticated using (true)","create policy \\"authenticated_write_llm_invocation_logs\\"\n  on llm_invocation_logs for all to authenticated using (true) with check (true)","create policy \\"authenticated_read_digest_logs\\"\n  on digest_logs for select to authenticated using (true)","create policy \\"authenticated_write_digest_logs\\"\n  on digest_logs for all to authenticated using (true) with check (true)","create policy \\"authenticated_read_llm_config\\"\n  on llm_config for select to authenticated using (true)","-- llm_config is write-protected from regular users — only service role (admin client) can write"}	rls_policies
004	{"-- WebriQ Central Hub — Schema Corrections\n-- Migration 004: Align schema with technical spec v0.1 (gaps found during COO/CTO doc review)\n\n-- ─── customers: add missing fields from tech spec §8 ─────────────────────────\nalter table customers\n  add column if not exists automation_toggle  boolean not null default false,\n  add column if not exists llm_excluded       boolean not null default false,\n  add column if not exists communication_tone text not null default 'formal'\n    check (communication_tone in ('formal', 'casual', 'technical')),\n  add column if not exists onboarding_status  jsonb not null default '{\\"completion_pct\\": 0, \\"missing_fields\\": [], \\"last_updated\\": null}'","-- ─── customer_products: add dedicated_developers and automation_toggle ────────\nalter table customer_products\n  add column if not exists dedicated_developers text[] not null default '{}'","-- ─── classification_records: llm_eligible → TEXT (YES | NO | HUMAN_ONLY) ─────\n-- Drop the old boolean column and add the correct TEXT one\nalter table classification_records\n  drop column if exists llm_eligible","alter table classification_records\n  add column if not exists llm_eligible text not null default 'NO'\n    check (llm_eligible in ('YES', 'NO', 'HUMAN_ONLY'))","-- Fix priority casing: CRITICAL | HIGH | NORMAL | LOW (uppercase, NORMAL not MEDIUM)\nalter table classification_records\n  drop constraint if exists classification_records_priority_check","alter table classification_records\n  add constraint classification_records_priority_check\n    check (priority in ('CRITICAL', 'HIGH', 'NORMAL', 'LOW'))","-- ─── requirements_assessments: add confidence_to_proceed ─────────────────────\nalter table requirements_assessments\n  add column if not exists confidence_to_proceed integer check (confidence_to_proceed between 0 and 100)","-- clarification_draft → JSONB (structured missing items + generated text)\nalter table requirements_assessments\n  drop column if exists clarification_draft","alter table requirements_assessments\n  add column if not exists clarification_draft jsonb","-- ─── implementation_plans: align status values with tech spec ─────────────────\nalter table implementation_plans\n  drop constraint if exists implementation_plans_status_check","alter table implementation_plans\n  alter column status set default 'PENDING_APPROVAL'","alter table implementation_plans\n  add constraint implementation_plans_status_check\n    check (status in ('PENDING_APPROVAL', 'APPROVED', 'REJECTED', 'EXECUTING', 'COMPLETE', 'FAILED'))","-- ─── execution_records: add missing fields from tech spec §8 ─────────────────\nalter table execution_records\n  add column if not exists outcome         text check (outcome in ('SUCCESS', 'PARTIAL', 'FAILED')),\n  add column if not exists outputs         jsonb not null default '{}',\n  add column if not exists what_was_done   text,\n  add column if not exists what_was_skipped text","-- ─── playbooks: add embedding and lifecycle fields from tech spec §6.5 ────────\nalter table playbooks\n  drop constraint if exists playbooks_source_check","alter table playbooks\n  add column if not exists embedding_summary          text,\n  add column if not exists original_task_description  text,\n  add column if not exists classification_applied     jsonb,\n  add column if not exists execution_outcome          text,\n  add column if not exists last_validated             date","-- Align status values: ACTIVE | STALE | ARCHIVED\nalter table playbooks\n  drop column if exists is_active","alter table playbooks\n  add column if not exists status text not null default 'ACTIVE'\n    check (status in ('ACTIVE', 'STALE', 'ARCHIVED'))","-- ─── llm_config: add provider column for multi-provider support ───────────────\nalter table llm_config\n  add column if not exists provider text not null default 'anthropic'\n    check (provider in ('anthropic', 'openai'))","-- Update seed to include provider\nupdate llm_config set provider = 'anthropic' where provider is null or provider = ''","-- ─── llm_invocation_logs: soft per-customer daily token budget ────────────────\n-- (referenced in tech spec §9: \\"Soft cap per-customer daily token budget with PM alert\\")\n-- The cap config is stored in customers table; actual tracking is via llm_invocation_logs\nalter table customers\n  add column if not exists daily_token_budget integer default null","-- ─── New: user_roles table (COO Specs §Access Control) ───────────────────────\n-- Role-based permissions: admin | pm | developer | client\ncreate table if not exists user_roles (\n  id         uuid primary key default gen_random_uuid(),\n  user_id    text not null,\n  role       text not null check (role in ('admin', 'pm', 'developer', 'client')),\n  created_at timestamptz not null default now()\n)","create unique index if not exists idx_user_roles_user_id_role on user_roles (user_id, role)","alter table user_roles enable row level security","create policy \\"authenticated_read_user_roles\\"\n  on user_roles for select to authenticated using (true)","create policy \\"authenticated_write_user_roles\\"\n  on user_roles for all to authenticated using (true) with check (true)"}	schema_corrections
005	{"-- Migration 005: Onboarding Storage Bucket + RLS Policies\n-- Creates the onboarding-assets bucket for file uploads during customer onboarding.\n-- Public read access (unauthenticated customers need to view their files).\n-- Authenticated write access via the upload API route.\n\n-- Create the storage bucket\nINSERT INTO storage.buckets (id, name, public, file_size_limit, allowed_mime_types)\nVALUES (\n  'onboarding-assets',\n  'onboarding-assets',\n  true,\n  26214400, -- 25MB\n  ARRAY[\n    'image/jpeg',\n    'image/png',\n    'image/gif',\n    'image/webp',\n    'image/svg+xml',\n    'application/pdf',\n    'application/msword',\n    'application/vnd.openxmlformats-officedocument.wordprocessingml.document',\n    'application/vnd.ms-excel',\n    'application/vnd.openxmlformats-officedocument.spreadsheetml.sheet'\n  ]\n)\nON CONFLICT (id) DO NOTHING","-- Policy: Public read access for onboarding-assets\n-- Anyone can view files in the onboarding-assets bucket (needed for unauthenticated customers)\nDROP POLICY IF EXISTS \\"Public read access for onboarding assets\\" ON storage.objects","CREATE POLICY \\"Public read access for onboarding assets\\"\n  ON storage.objects\n  FOR SELECT\n  USING (bucket_id = 'onboarding-assets')","-- Policy: Authenticated insert for onboarding-assets\n-- Any authenticated user can upload to onboarding-assets\n-- The upload API route uses the service role (admin client) for actual uploads,\n-- but this policy is here for future direct authenticated uploads.\nDROP POLICY IF EXISTS \\"Authenticated insert to onboarding assets\\" ON storage.objects","CREATE POLICY \\"Authenticated insert to onboarding assets\\"\n  ON storage.objects\n  FOR INSERT\n  WITH CHECK (bucket_id = 'onboarding-assets')","-- Policy: Authenticated delete for onboarding-assets\nDROP POLICY IF EXISTS \\"Authenticated delete from onboarding assets\\" ON storage.objects","CREATE POLICY \\"Authenticated delete from onboarding assets\\"\n  ON storage.objects\n  FOR DELETE\n  USING (bucket_id = 'onboarding-assets')"}	onboarding_storage
006	{"-- ─── Add completed_percentage to customer_products ──────────────────────────\n-- Stores real field-completion progress (0–100) per product so the PM\n-- dashboard can show per-product bars without re-computing from onboarding_data.\nalter table customer_products\n  add column if not exists completed_percentage numeric(5,2) not null default 0\n    check (completed_percentage >= 0 and completed_percentage <= 100)","-- ─── Enable Supabase Realtime for PM dashboard live-update subscription ──────\n-- Allows the PM dashboard to receive UPDATE events as customers fill the form.\nalter publication supabase_realtime add table customer_products"}	product_completion_percentage
007	{"-- WebriQ Central Hub — Migration 007: hub_users\n-- Internal user profiles with role assignment and Zoho identity linkage.\n-- id FK references auth.users so rows are deleted automatically when the auth user is removed.\n\ncreate table if not exists public.hub_users (\n  id            uuid primary key references auth.users(id) on delete cascade,\n  email         text not null,\n  display_name  text,\n  role          text not null default 'pm'\n    check (role in ('admin', 'pm', 'developer', 'client')),\n  zoho_user_id  text,\n  created_at    timestamptz not null default now(),\n  updated_at    timestamptz not null default now()\n)","create trigger set_updated_at_hub_users\n  before update on public.hub_users\n  for each row execute function update_updated_at_column()","alter table public.hub_users enable row level security","-- Users can read only their own row; role writes are service-role only (via Supabase Dashboard)\ncreate policy \\"users_read_own\\"\n  on public.hub_users for select to authenticated\n  using (id = auth.uid())","-- Auto-insert on first login — fires for both Zoho OAuth and email/password sign-ups.\n-- security definer + fixed search_path required for triggers on auth.users writing to public schema.\ncreate or replace function public.handle_new_hub_user()\nreturns trigger language plpgsql security definer set search_path = public as $$\nbegin\n  insert into public.hub_users (id, email, display_name, zoho_user_id)\n  values (\n    new.id,\n    new.email,\n    coalesce(new.raw_user_meta_data->>'full_name', new.raw_user_meta_data->>'name'),\n    new.raw_user_meta_data->>'provider_id'\n  )\n  on conflict (id) do nothing;\n  return new;\nend;\n$$","create trigger on_auth_user_created\n  after insert on auth.users\n  for each row execute procedure public.handle_new_hub_user()"}	hub_users
008	{"-- WebriQ Central Hub — Migration 008: Fix hub_users trigger + backfill\n-- Fixes three issues:\n--   1. zoho_user_id was reading nonexistent raw_user_meta_data.provider_id → use sub\n--   2. display_name was NULL for Zoho users → fallback to email prefix\n--   3. Email-first/Zoho-later users never got updated → add AFTER UPDATE trigger\n\nbegin","-- ── 1. Drop old trigger + function ─────────────────────────────────────────\n\ndrop trigger if exists on_auth_user_created on auth.users","drop trigger if exists on_auth_user_updated on auth.users","drop function if exists public.handle_new_hub_user()","-- ── 2. Create corrected function (used by both INSERT and UPDATE triggers) ──\n\ncreate or replace function public.handle_new_hub_user()\nreturns trigger language plpgsql security definer set search_path = public as $$\ndeclare\n  v_display_name text;\n  v_zoho_user_id text;\nbegin\n  -- display_name: try Zoho name fields, then email signup fields, then email prefix.\n  -- Note: Zoho OIDC doesn't send a name — the callback page fetches the real name\n  -- from Zoho's /oauth/user/info endpoint and updates both hub_users + auth.users.\n  v_display_name := coalesce(\n    new.raw_user_meta_data->>'full_name',\n    new.raw_user_meta_data->>'name',\n    new.raw_user_meta_data->>'display_name',\n    split_part(new.email, '@', 1)\n  );\n\n  -- zoho_user_id: Zoho sends the user's unique ID in the 'sub' claim.\n  -- Format is \\"{ZUID}.{identifier}\\" — we want just the ZUID part.\n  v_zoho_user_id := split_part(new.raw_user_meta_data->>'sub', '.', 1);\n\n  insert into public.hub_users (id, email, display_name, role, zoho_user_id)\n  values (\n    new.id,\n    new.email,\n    v_display_name,\n    'pm',\n    v_zoho_user_id\n  )\n  on conflict (id) do update set\n    email        = excluded.email,\n    display_name = coalesce(hub_users.display_name, excluded.display_name),\n    zoho_user_id = coalesce(hub_users.zoho_user_id, excluded.zoho_user_id),\n    updated_at   = now();\n\n  return new;\nend;\n$$","-- ── 3. Re-create AFTER INSERT trigger ──────────────────────────────────────\n\ncreate trigger on_auth_user_created\n  after insert on auth.users\n  for each row execute procedure public.handle_new_hub_user()","-- ── 4. AFTER UPDATE trigger — catches email-first/Zoho-later linking ────────\n\ncreate trigger on_auth_user_updated\n  after update of raw_user_meta_data on auth.users\n  for each row\n  when (old.raw_user_meta_data is distinct from new.raw_user_meta_data)\n  execute procedure public.handle_new_hub_user()","-- ── 5. Backfill existing hub_users with corrected data ─────────────────────\n\n-- Extract just the ZUID from sub (e.g., \\"908075526.1344712556\\" → \\"908075526\\")\nupdate public.hub_users hu\nset\n  zoho_user_id = split_part(au.raw_user_meta_data->>'sub', '.', 1),\n  updated_at   = now()\nfrom auth.users au\nwhere hu.id = au.id\n  and au.raw_user_meta_data->>'sub' is not null\n  and (hu.zoho_user_id is null or hu.zoho_user_id like '%.%')","-- Fill NULL display_names with email prefix fallback\nupdate public.hub_users\nset\n  display_name = coalesce(display_name, split_part(email, '@', 1)),\n  updated_at   = now()\nwhere display_name is null",commit}	fix_hub_users_trigger
009	{"-- WebriQ Central Hub — Migration 009: force_logout_all_except\n-- Admin utility to force-logout all users except a specified one.\n-- Deletes all sessions and refresh tokens from auth schema for non-exempt users,\n-- causing their next request to fail JWT validation via getClaims().\n\ncreate or replace function public.force_logout_all_except(\n  exclude_user_id uuid\n)\nreturns table(\n  action text,\n  count bigint\n)\nlanguage plpgsql\nsecurity definer\nset search_path = 'auth', 'public'\nas $$\ndeclare\n  session_count bigint;\n  refresh_count bigint;\nbegin\n  -- Delete refresh tokens for non-exempt users (must be first — sessions reference them)\n  -- auth.refresh_tokens.user_id is varchar, so cast exclude_user_id for comparison\n  with deleted as (\n    delete from auth.refresh_tokens\n    where user_id != exclude_user_id::text\n    returning 1\n  )\n  select count(*) into refresh_count from deleted;\n\n  -- Delete sessions for non-exempt users\n  with deleted as (\n    delete from auth.sessions\n    where user_id != exclude_user_id\n    returning 1\n  )\n  select count(*) into session_count from deleted;\n\n  return query\n    select 'sessions_deleted'::text, session_count\n    union all\n    select 'refresh_tokens_deleted'::text, refresh_count;\nend;\n$$"}	force_logout_function
010	{"-- Migration 010: Add completed_onboarding status + drop zoho_account_id\n-- completed_onboarding sits between onboarding and active — PM must manually create Zoho projects to advance.\n\n-- Alter customers.status CHECK to include the new intermediate state\nalter table customers drop constraint if exists customers_status_check","alter table customers add constraint customers_status_check\n  check (status in ('active', 'inactive', 'onboarding', 'completed_onboarding'))","-- zoho_account_id is not used — customers have no Zoho account; the Hub owns the Zoho OAuth identity.\n-- The Zoho Desk webhook lookup via this column is also removed (see webhooks/route.ts).\nalter table customers drop column if exists zoho_account_id"}	completed_onboarding_status
011	{"-- Migration 011: Add raw_response column to requirements_assessments\n-- Stores the raw LLM output before structured parsing — useful for debugging\n-- and prompt improvement loops (Sprint 3, M3).\n\nalter table requirements_assessments\n  add column if not exists raw_response jsonb"}	assessment_raw_response
012	{"-- Migration 012: Enable pg_cron + pg_net for daily digest scheduling (Sprint 3, M4)\n--\n-- SETUP REQUIRED AFTER RUNNING THIS MIGRATION:\n-- 1. Enable these extensions in Supabase Dashboard → Database → Extensions if not already active.\n-- 2. After deploying your app to Vercel, update the cron job URL via the Supabase SQL editor:\n--\n--    select cron.alter_job(\n--      (select jobid from cron.job where jobname = 'daily-pm-digest'),\n--      command := format(\n--        $cmd$\n--        select net.http_post(\n--          url     := '%s/api/digest',\n--          body    := '{\\"type\\":\\"pm\\"}'::jsonb,\n--          headers := '{\\"x-digest-secret\\":\\"%s\\",\\"content-type\\":\\"application/json\\"}'::jsonb\n--        )\n--        $cmd$,\n--        'https://YOUR_VERCEL_APP_URL',  -- replace with actual URL\n--        'YOUR_DIGEST_SECRET'            -- matches DIGEST_SECRET env var\n--      )\n--    );\n--\n-- 3. For local development, use the \\"Trigger Digest\\" button on the PM home page.\n--    pg_cron cannot reach localhost from Supabase cloud.\n\ncreate extension if not exists pg_cron","create extension if not exists pg_net","-- Schedule daily PM digest at 08:00 UTC.\n-- The URL below is a placeholder — update it via cron.alter_job() after deployment (see above).\nselect cron.schedule(\n  'daily-pm-digest',\n  '0 8 * * *',\n  $job$\n  select net.http_post(\n    url     := 'https://REPLACE_WITH_APP_URL/api/digest',\n    body    := '{\\"type\\":\\"pm\\"}'::jsonb,\n    headers := '{\\"x-digest-secret\\":\\"REPLACE_WITH_DIGEST_SECRET\\",\\"content-type\\":\\"application/json\\"}'::jsonb\n  )\n  $job$\n)"}	pg_cron_digest
013	{"-- WebriQ Central Hub — Sprint 4 Part 2\n-- Migration 013: Zoho task sync columns + classification status expansion\n\n-- Add Zoho sync columns to implementation_plans\nalter table implementation_plans\n  add column if not exists zoho_task_id     text,\n  add column if not exists direct_zoho_edit boolean not null default false","create index if not exists idx_implementation_plans_zoho_task_id\n  on implementation_plans (zoho_task_id)\n  where zoho_task_id is not null","-- Expand classification_records status check to include pipeline + PM action statuses.\n-- Original constraint ('pending', 'reviewed', 'rejected') from migration 001 is too narrow —\n-- task 025 already writes 'planning' and 'approved' to this column.\nalter table classification_records\n  drop constraint if exists classification_records_status_check","alter table classification_records\n  add constraint classification_records_status_check\n    check (status in (\n      'pending', 'classifying', 'classified', 'reviewed', 'rejected',\n      'planning', 'approved',\n      'open', 'on_hold', 'active', 'review', 'closed'\n    ))"}	zoho_task_sync
014	{"-- WebriQ Central Hub — Sprint 5\n-- Migration 014: Execution engine additions\n\n-- Circuit breaker: tripped when 3 consecutive executions fail for a customer\nalter table customers\n  add column if not exists automation_paused boolean not null default false","-- Constrain execution_records.status to valid pipeline values\n-- (drop first to make this idempotent on re-runs)\nalter table execution_records\n  drop constraint if exists execution_records_status_check","alter table execution_records\n  add constraint execution_records_status_check\n    check (status in ('PENDING', 'RUNNING', 'COMPLETED', 'PARTIAL_EXECUTION', 'FAILED', 'REVERTED'))"}	sprint5_execution
015	{"-- WebriQ Central Hub — Sprint 5\n-- Migration 015: Reply drafts — PM-reviewed client updates before Cliq send (M8)\n\ncreate table if not exists reply_drafts (\n  id                  uuid primary key default gen_random_uuid(),\n  classification_id   uuid not null\n                        references classification_records(id) on delete cascade,\n  customer_id         text not null\n                        references customers(customer_id) on delete cascade,\n  execution_record_id uuid\n                        references execution_records(id) on delete cascade,\n  draft_content       text not null,\n  pm_edited_content   text,\n  pm_diff             text,\n  status              text not null default 'DRAFT'\n                        check (status in ('DRAFT', 'SENT', 'DISCARDED')),\n  sent_at             timestamptz,\n  created_at          timestamptz not null default now()\n)","create index if not exists idx_reply_drafts_classification_id\n  on reply_drafts (classification_id)","create index if not exists idx_reply_drafts_customer_id\n  on reply_drafts (customer_id)","alter table reply_drafts enable row level security","create policy \\"authenticated_read_reply_drafts\\"\n  on reply_drafts for select to authenticated using (true)","create policy \\"authenticated_write_reply_drafts\\"\n  on reply_drafts for all to authenticated using (true) with check (true)"}	reply_drafts
016	{"-- WebriQ Central Hub — Migration 016: KB Storage bucket + policies (Sprint 6, M10)\n\n-- Create the kb bucket (private — no public URLs; files served via signed URLs)\ninsert into storage.buckets (id, name, public)\nvalues ('kb', 'kb', false)\non conflict (id) do nothing","-- hub_users with role 'pm' or 'developer' can upload to kb/global/\ncreate policy \\"kb_global_upload\\"\n  on storage.objects for insert\n  to authenticated\n  with check (\n    bucket_id = 'kb'\n    and (storage.foldername(name))[1] = 'global'\n    and exists (\n      select 1 from public.hub_users\n      where id = auth.uid()\n        and role in ('pm', 'developer', 'admin')\n    )\n  )","-- PM can upload to kb/customers/{customerId}/\ncreate policy \\"kb_customer_upload_pm\\"\n  on storage.objects for insert\n  to authenticated\n  with check (\n    bucket_id = 'kb'\n    and (storage.foldername(name))[1] = 'customers'\n    and exists (\n      select 1 from public.hub_users\n      where id = auth.uid()\n        and role in ('pm', 'admin')\n    )\n  )","-- Developer can upload to kb/customers/{customerId}/\ncreate policy \\"kb_customer_upload_dev\\"\n  on storage.objects for insert\n  to authenticated\n  with check (\n    bucket_id = 'kb'\n    and (storage.foldername(name))[1] = 'customers'\n    and exists (\n      select 1 from public.hub_users\n      where id = auth.uid()\n        and role in ('developer', 'admin')\n    )\n  )","-- All hub_users can read all kb files\ncreate policy \\"kb_read_all\\"\n  on storage.objects for select\n  to authenticated\n  using (\n    bucket_id = 'kb'\n    and exists (\n      select 1 from public.hub_users where id = auth.uid()\n    )\n  )"}	kb_storage
017	{"-- WebriQ Central Hub — Migration 017: KB lint logs + weekly cron (Sprint 6, M10)\n\ncreate table if not exists kb_lint_logs (\n  id            uuid primary key default gen_random_uuid(),\n  report        jsonb not null default '{}',\n  files_audited integer not null default 0,\n  model_used    text,\n  input_tokens  integer,\n  output_tokens integer,\n  created_at    timestamptz not null default now()\n)","create index if not exists idx_kb_lint_logs_created_at on kb_lint_logs (created_at desc)","-- Enable RLS (admin-only read via service role; no user-facing policy needed at Phase 1)\nalter table public.kb_lint_logs enable row level security","-- Weekly wiki lint: Monday 06:00 UTC\n-- pg_cron and pg_net must already be enabled (migration 012 enables them).\n-- Update the URL via cron.alter_job() after deployment (same pattern as migration 012).\nselect cron.schedule(\n  'weekly-wiki-lint',\n  '0 6 * * 1',\n  $job$\n  select net.http_post(\n    url     := 'https://REPLACE_WITH_APP_URL/api/kb/lint',\n    body    := '{}'::jsonb,\n    headers := '{\\"x-digest-secret\\":\\"REPLACE_WITH_DIGEST_SECRET\\",\\"content-type\\":\\"application/json\\"}'::jsonb\n  )\n  $job$\n)"}	kb_lint
018	{"-- WebriQ Central Hub — Migration 018: Hub metrics view (Sprint 6, M10)\n\ncreate or replace view vw_hub_metrics as\nselect\n  -- 1. Total customers onboarded\n  (select count(*) from customers where status != 'inactive') as customers_total,\n\n  -- 2. Total tasks classified\n  (select count(*) from classification_records) as classifications_total,\n\n  -- 3. LLM-eligible task rate (%)\n  (\n    select round(\n      100.0 * count(*) filter (where llm_eligible = 'YES') / nullif(count(*), 0),\n      1\n    )\n    from classification_records\n  ) as llm_eligible_rate_pct,\n\n  -- 4. Average classification confidence score\n  (\n    select round(avg(confidence_score)::numeric, 2)\n    from classification_records\n    where confidence_score is not null\n  ) as avg_classification_confidence,\n\n  -- 5. Total assessments run\n  (select count(*) from requirements_assessments) as assessments_total,\n\n  -- 6. Plan approval rate (%)\n  (\n    select round(\n      100.0 * count(*) filter (where status in ('APPROVED', 'EXECUTING', 'COMPLETE'))\n             / nullif(count(*) filter (where status != 'draft'), 0),\n      1\n    )\n    from implementation_plans\n  ) as plan_approval_rate_pct,\n\n  -- 7. Plan rejection rate (%)\n  (\n    select round(\n      100.0 * count(*) filter (where status = 'REJECTED')\n             / nullif(count(*) filter (where status != 'draft'), 0),\n      1\n    )\n    from implementation_plans\n  ) as plan_rejection_rate_pct,\n\n  -- 8. Total executions completed\n  (select count(*) from execution_records where status in ('COMPLETED', 'PARTIAL_EXECUTION')) as executions_completed,\n\n  -- 9. Execution success rate (%)\n  (\n    select round(\n      100.0 * count(*) filter (where status = 'COMPLETED')\n             / nullif(count(*) filter (where status != 'PENDING'), 0),\n      1\n    )\n    from execution_records\n  ) as execution_success_rate_pct,\n\n  -- 10. Total LLM cost USD (all time)\n  (select round(sum(cost_usd)::numeric, 4) from llm_invocation_logs where status = 'success') as llm_cost_total_usd,\n\n  -- 11. Total LLM cost USD (this month)\n  (\n    select round(sum(cost_usd)::numeric, 4)\n    from llm_invocation_logs\n    where status = 'success'\n      and created_at >= date_trunc('month', now())\n  ) as llm_cost_month_usd"}	metrics_view
019	{"-- WebriQ Central Hub — Sprint 6 KB Seed: Content Update + Settings Change playbooks\n-- Global playbooks (customer_id = null) — manual source, active\n\ninsert into playbooks (customer_id, task_type, title, content, version, status, source)\nvalues\n(\n  null,\n  'CONTENT_UPDATE',\n  'Content Update Playbook',\n  E'# Content Update Playbook\\\\n\\\\n'\n  '## When to use\\\\nUse for any request that modifies copy, images, or structured content in Sanity CMS without changing site structure or code.\\\\n\\\\n'\n  '## Steps\\\\n'\n  '1. Confirm the exact pages or content blocks to be updated with the PM.\\\\n'\n  '2. Pull the latest content from Sanity for the target dataset.\\\\n'\n  '3. Apply changes in the Sanity Studio or via the Content Lake API.\\\\n'\n  '4. Preview changes in the Sanity Preview URL if available.\\\\n'\n  '5. Publish the document in Sanity Studio.\\\\n'\n  '6. Verify on the live site within 5 minutes (CDN propagation).\\\\n'\n  '7. Close the Zoho task and add a comment with the Sanity document ID and the change summary.\\\\n\\\\n'\n  '## Common errors\\\\n'\n  '- **Publish blocked:** Another draft is locked — discard or merge the conflicting draft first.\\\\n'\n  '- **Image not appearing:** Check the asset pipeline is not filtered by locale or device type.\\\\n\\\\n'\n  '## Acceptance criteria\\\\n'\n  '- Content visible on production URL within 10 minutes of publish.\\\\n'\n  '- No console errors on the updated page.',\n  1,\n  'ACTIVE',\n  'manual'\n),\n(\n  null,\n  'SETTINGS_CHANGE',\n  'Settings Change Playbook',\n  E'# Settings Change Playbook\\\\n\\\\n'\n  '## When to use\\\\nUse for any request that modifies environment variables, feature flags, third-party integration credentials, or CMS global settings without deploying new code.\\\\n\\\\n'\n  '## Steps\\\\n'\n  '1. Identify the setting key and target environment (staging vs production).\\\\n'\n  '2. Record the current value in the Zoho task notes as a rollback reference.\\\\n'\n  '3. Apply the change:\\\\n'\n  '   - For Vercel env vars: update via Vercel Dashboard → Project Settings → Environment Variables.\\\\n'\n  '   - For Sanity global config: update via the Settings singleton document in Sanity Studio.\\\\n'\n  '   - For Zoho settings: update via Zoho portal configuration.\\\\n'\n  '4. Trigger a redeployment if the env var is build-time (not runtime).\\\\n'\n  '5. Smoke-test the affected feature on the target environment.\\\\n'\n  '6. Close the Zoho task with before/after values documented in the comment.\\\\n\\\\n'\n  '## Rollback\\\\n'\n  'Revert to the recorded value from step 2. Redeploy if necessary.\\\\n\\\\n'\n  '## Acceptance criteria\\\\n'\n  '- The affected feature behaves as expected with the new setting.\\\\n'\n  '- No regression in related features.',\n  1,\n  'ACTIVE',\n  'manual'\n)\non conflict do nothing"}	kb_playbook_seed
020	{"-- Add 'pending' as a valid role value for hub_users\n-- Pending users are Zoho Employee+Employee logins awaiting admin approval.\nALTER TABLE hub_users DROP CONSTRAINT hub_users_role_check","ALTER TABLE hub_users\n  ADD CONSTRAINT hub_users_role_check\n  CHECK (role IN ('admin', 'pm', 'dev', 'pending'))"}	hub_users_pending_role
021	{"create table if not exists customer_assets (\n  id uuid primary key default gen_random_uuid(),\n  customer_id text not null references customers(customer_id) on delete cascade,\n  type text not null check (type in ('file', 'link', 'credential')),\n  label text not null,\n  value text not null,\n  masked boolean not null default false,\n  created_at timestamptz not null default now()\n)","alter table customer_assets enable row level security","create policy \\"Authenticated users can manage customer assets\\"\n  on customer_assets for all\n  using (auth.role() = 'authenticated')\n  with check (auth.role() = 'authenticated')"}	customer_assets
022	{"-- Migration 022: Expand classification_records.source check to include 'hub_manual'\n-- Needed for PM-created tasks from the Hub (task 050).\nalter table classification_records\n  drop constraint if exists classification_records_source_check","alter table classification_records\n  add constraint classification_records_source_check\n    check (source in ('zoho_desk', 'zoho_projects', 'hub_manual'))"}	classification_source_hub_manual
023	{"-- Expand customer_products.status CHECK constraint to allow 'archived' for soft-delete.\nALTER TABLE customer_products DROP CONSTRAINT IF EXISTS customer_products_status_check","ALTER TABLE customer_products ADD CONSTRAINT customer_products_status_check\n  CHECK (status IN ('active', 'inactive', 'archived'))"}	customer_products_archive_status
024	{"-- 024_customer_projects_table.sql\n-- Create customer_projects table as a customer-level concept (not per-product).\n-- Projects carry zoho_project_id, sanity_project_id, github_repo, dedicated_developers\n-- which were previously (incorrectly) columns on customer_products.\n\ncreate table if not exists customer_projects (\n  id                   uuid primary key default gen_random_uuid(),\n  customer_id          text not null references customers (customer_id) on delete cascade,\n  project_name         text not null,\n  project_type         text not null check (project_type in ('Content Site', 'Ecommerce (B2C)', 'Ecommerce (B2B)', 'Custom App')),\n  zoho_project_id      text,\n  sanity_project_id    text,\n  github_repo          text,\n  dedicated_developers text[] not null default '{}',\n  created_at           timestamptz not null default now(),\n  updated_at           timestamptz not null default now()\n)","create index if not exists idx_customer_projects_customer_id on customer_projects (customer_id)","-- RLS: mirror customer_products policies\nalter table customer_projects enable row level security","create policy \\"Authenticated users can read customer_projects\\"\n  on customer_projects for select\n  to authenticated\n  using (true)","create policy \\"Service role has full access to customer_projects\\"\n  on customer_projects for all\n  to service_role\n  using (true)\n  with check (true)","-- Drop migrated columns from customer_products (clean drop, no data to preserve)\nalter table customer_products\n  drop column if exists zoho_project_id,\n  drop column if exists sanity_project_id,\n  drop column if exists github_repo,\n  drop column if exists dedicated_developers"}	customer_projects_table
025	{"-- Migration 025: v2.0 Schema — Sprint 0A\n-- Deploys all new tables, renames customer_projects → projects, widens source enum.\n-- §10.6 codebase mapping: https://github.com/webriq/central-hub/blob/main/_docs/plan-v2/WebriQ-Central-Hub-Spec-v2.md#106\n\n-- ─── profiles ─────────────────────────────────────────────────────────────────\n-- Extends auth.users with role and optional customer link for client users.\ncreate table profiles (\n  id uuid primary key references auth.users(id) on delete cascade,\n  role text not null check (role in ('admin', 'hr', 'pm', 'developer', 'client')),\n  full_name text,\n  avatar_url text,\n  customer_id text references customers(customer_id) on delete set null,\n  created_at timestamptz not null default now(),\n  updated_at timestamptz not null default now()\n)","-- ─── projects (was customer_projects) ─────────────────────────────────────────\nalter table customer_projects rename to projects","alter table projects rename column project_name to name","alter table projects\n  add column status text not null check (status in ('active', 'on_hold', 'completed', 'archived')) default 'active',\n  add column customer_product_id uuid references customer_products(id) on delete set null,\n  add column description text,\n  add column created_by uuid references auth.users(id) on delete set null","-- Update FK constraint name for clarity\nalter table projects rename constraint customer_projects_customer_id_fkey to projects_customer_id_fkey","-- ─── classification_records.source — widen enum ───────────────────────────────\n-- Keep existing zoho_* values during v0.1→v2 transition; retire at Phase 1D cutover.\nalter table classification_records\n  drop constraint classification_records_source_check","alter table classification_records\n  add constraint classification_records_source_check\n    check (source in ('zoho_desk', 'zoho_projects', 'hub_manual', 'portal', 'email', 'manual', 'recurring'))","-- ─── tasks ────────────────────────────────────────────────────────────────────\ncreate table tasks (\n  id uuid primary key default gen_random_uuid(),\n  project_id uuid not null references projects(id) on delete cascade,\n  ticket_id uuid null,\n  parent_task_id uuid null references tasks(id) on delete cascade,\n  title text not null,\n  description text,\n  task_type text,\n  priority text not null check (priority in ('low', 'normal', 'high', 'critical')) default 'normal',\n  status text not null check (status in ('backlog', 'todo', 'in_progress', 'for_review', 'done', 'cancelled')) default 'backlog',\n  assignees uuid[],\n  due_date date,\n  estimate_hours numeric(5, 2),\n  labels text[],\n  position numeric,\n  classification_id uuid references classification_records(id) on delete set null,\n  github_pr_url text,\n  preview_url text,\n  created_by uuid references auth.users(id) on delete set null,\n  created_at timestamptz not null default now(),\n  updated_at timestamptz not null default now()\n)","create table task_comments (\n  id uuid primary key default gen_random_uuid(),\n  task_id uuid not null references tasks(id) on delete cascade,\n  author_id uuid not null references auth.users(id) on delete cascade,\n  body text not null,\n  created_at timestamptz not null default now()\n)","create table attachments (\n  id uuid primary key default gen_random_uuid(),\n  entity_type text not null,\n  entity_id uuid not null,\n  storage_path text not null,\n  filename text not null,\n  size bigint,\n  uploaded_by uuid references auth.users(id) on delete set null,\n  created_at timestamptz not null default now()\n)","create table time_logs (\n  id uuid primary key default gen_random_uuid(),\n  task_id uuid not null references tasks(id) on delete cascade,\n  project_id uuid not null references projects(id) on delete cascade,\n  employee_id uuid references auth.users(id) on delete set null,\n  date_logged date not null,\n  hours numeric(5, 2) not null,\n  billable boolean not null default true,\n  note text,\n  source text not null check (source in ('timer', 'manual')) default 'manual',\n  timesheet_id uuid null,\n  created_at timestamptz not null default now()\n)","-- ─── tickets ──────────────────────────────────────────────────────────────────\ncreate table tickets (\n  id uuid primary key default gen_random_uuid(),\n  ticket_number serial unique,\n  customer_id text not null references customers(customer_id) on delete cascade,\n  customer_product_id uuid references customer_products(id) on delete set null,\n  subject text not null,\n  channel text not null check (channel in ('portal', 'email', 'manual')),\n  priority text not null check (priority in ('low', 'normal', 'high', 'critical')) default 'normal',\n  status text not null check (status in ('new', 'open', 'waiting_on_client', 'waiting_on_us', 'resolved', 'closed')) default 'new',\n  requester_email text,\n  requester_profile_id uuid references profiles(id) on delete set null,\n  sla_due_at timestamptz,\n  first_response_at timestamptz,\n  resolved_at timestamptz,\n  classification_id uuid references classification_records(id) on delete set null,\n  created_at timestamptz not null default now(),\n  updated_at timestamptz not null default now()\n)","-- Deferred FK from tasks to tickets (tickets must exist first)\nalter table tasks\n  add constraint tasks_ticket_id_fkey\n  foreign key (ticket_id) references tickets(id) on delete set null","create table ticket_messages (\n  id uuid primary key default gen_random_uuid(),\n  ticket_id uuid not null references tickets(id) on delete cascade,\n  author_type text not null check (author_type in ('client', 'staff', 'system', 'llm_draft')),\n  author_id uuid null references auth.users(id) on delete set null,\n  body text not null,\n  email_message_id text null,\n  visibility text not null check (visibility in ('public', 'internal')) default 'public',\n  created_at timestamptz not null default now()\n)","-- ─── HR schema ────────────────────────────────────────────────────────────────\ncreate schema if not exists hr","create table hr.employees (\n  id uuid primary key default gen_random_uuid(),\n  profile_id uuid not null references profiles(id) on delete cascade,\n  employee_number text unique,\n  full_name text not null,\n  department text,\n  position text,\n  employment_type text not null check (employment_type in ('full_time', 'part_time', 'contract')),\n  manager_id uuid null references hr.employees(id) on delete set null,\n  date_hired date,\n  date_separated date null,\n  status text not null check (status in ('active', 'on_leave', 'separated')) default 'active',\n  emergency_contact jsonb,\n  meta jsonb,\n  created_at timestamptz not null default now(),\n  updated_at timestamptz not null default now()\n)","create table hr.attendance_punches (\n  id uuid primary key default gen_random_uuid(),\n  employee_id uuid not null references hr.employees(id) on delete cascade,\n  punched_at timestamptz not null,\n  direction text not null check (direction in ('in', 'out')),\n  ip inet null,\n  geo point null,\n  device text null\n)","create table hr.attendance_days (\n  id uuid primary key default gen_random_uuid(),\n  employee_id uuid not null references hr.employees(id) on delete cascade,\n  work_date date not null,\n  status text not null check (status in ('present', 'late', 'half_day', 'absent', 'on_leave', 'holiday', 'rest_day')),\n  first_in timestamptz,\n  last_out timestamptz,\n  total_hours numeric(5, 2),\n  correction_of uuid null references hr.attendance_days(id),\n  corrected_by uuid null references auth.users(id),\n  unique (employee_id, work_date)\n)","create table hr.leave_types (\n  id uuid primary key default gen_random_uuid(),\n  name text not null,\n  code text not null unique,\n  paid boolean not null default true,\n  accrual_rule jsonb,\n  carry_over_cap numeric,\n  active boolean not null default true\n)","create table hr.leave_balances (\n  id uuid primary key default gen_random_uuid(),\n  employee_id uuid not null references hr.employees(id) on delete cascade,\n  leave_type_id uuid not null references hr.leave_types(id) on delete cascade,\n  year int not null,\n  accrued numeric(5, 2) not null default 0,\n  used numeric(5, 2) not null default 0,\n  balance numeric(5, 2) generated always as (accrued - used) stored,\n  unique (employee_id, leave_type_id, year)\n)","create table hr.leave_requests (\n  id uuid primary key default gen_random_uuid(),\n  employee_id uuid not null references hr.employees(id) on delete cascade,\n  leave_type_id uuid not null references hr.leave_types(id) on delete restrict,\n  start_date date not null,\n  end_date date not null,\n  half_day boolean not null default false,\n  reason text,\n  attachment_path text null,\n  status text not null check (status in ('pending', 'approved', 'rejected', 'cancelled')) default 'pending',\n  approver_id uuid null references auth.users(id),\n  decided_at timestamptz null,\n  decision_note text null,\n  created_at timestamptz not null default now()\n)","create table hr.timesheets (\n  id uuid primary key default gen_random_uuid(),\n  employee_id uuid not null references hr.employees(id) on delete cascade,\n  week_start date not null,\n  status text not null check (status in ('draft', 'submitted', 'approved', 'locked')) default 'draft',\n  submitted_at timestamptz null,\n  approved_by uuid null references auth.users(id),\n  approved_at timestamptz null,\n  unique (employee_id, week_start)\n)","-- Deferred FK from time_logs to hr.timesheets\nalter table time_logs\n  add constraint time_logs_timesheet_id_fkey\n  foreign key (timesheet_id) references hr.timesheets(id) on delete set null","create table hr.announcements (\n  id uuid primary key default gen_random_uuid(),\n  title text not null,\n  body text not null,\n  pinned boolean not null default false,\n  author_id uuid not null references auth.users(id),\n  published_at timestamptz not null default now()\n)","create table hr.hr_requests (\n  id uuid primary key default gen_random_uuid(),\n  employee_id uuid not null references hr.employees(id) on delete cascade,\n  request_type text not null,\n  details jsonb,\n  status text not null check (status in ('pending', 'approved', 'rejected', 'cancelled')) default 'pending',\n  approver_id uuid null references auth.users(id),\n  created_at timestamptz not null default now()\n)","-- ─── Platform plumbing ────────────────────────────────────────────────────────\ncreate table event_bus (\n  id bigserial primary key,\n  event_type text not null,\n  entity_type text not null,\n  entity_id uuid not null,\n  payload jsonb,\n  status text not null check (status in ('pending', 'processing', 'done', 'failed')) default 'pending',\n  attempts int not null default 0,\n  available_at timestamptz not null default now(),\n  created_at timestamptz not null default now()\n)","create table notifications (\n  id uuid primary key default gen_random_uuid(),\n  recipient_id uuid not null references profiles(id) on delete cascade,\n  event_type text not null,\n  title text not null,\n  body text not null,\n  link text,\n  read_at timestamptz null,\n  channels_sent text[],\n  created_at timestamptz not null default now()\n)","create table notification_preferences (\n  profile_id uuid not null references profiles(id) on delete cascade,\n  event_type text not null,\n  in_app boolean not null default true,\n  push boolean not null default false,\n  email boolean not null default false,\n  primary key (profile_id, event_type)\n)","create table push_subscriptions (\n  id uuid primary key default gen_random_uuid(),\n  profile_id uuid not null references profiles(id) on delete cascade,\n  endpoint text not null,\n  keys jsonb not null,\n  created_at timestamptz not null default now()\n)","create table audit_logs (\n  id uuid primary key default gen_random_uuid(),\n  actor_id uuid references auth.users(id) on delete set null,\n  action text not null,\n  entity_type text not null,\n  entity_id uuid not null,\n  before jsonb,\n  after jsonb,\n  created_at timestamptz not null default now()\n)","-- ─── Enable RLS on all new tables (policies in migration 026) ─────────────────\nalter table profiles enable row level security","alter table tasks enable row level security","alter table task_comments enable row level security","alter table attachments enable row level security","alter table time_logs enable row level security","alter table tickets enable row level security","alter table ticket_messages enable row level security","alter table event_bus enable row level security","alter table notifications enable row level security","alter table notification_preferences enable row level security","alter table push_subscriptions enable row level security","alter table audit_logs enable row level security","alter table hr.employees enable row level security","alter table hr.attendance_punches enable row level security","alter table hr.attendance_days enable row level security","alter table hr.leave_types enable row level security","alter table hr.leave_balances enable row level security","alter table hr.leave_requests enable row level security","alter table hr.timesheets enable row level security","alter table hr.announcements enable row level security","alter table hr.hr_requests enable row level security"}	v2_schema
026	{"-- Migration 026: v2.0 RLS Policies v1 + Auth Trigger\n-- Sprint 0A — completes §8.2 role matrix for all tables enabled in migration 025.\n-- RLS was already enabled on all tables in migration 025 (comment: \\"policies in migration 026\\").\n-- `projects` table: had permissive policy from migration 024 — drop it, replace with role matrix.\n\n-- ─── Helper: get current user's role from profiles ────────────────────────────\n-- security definer so this can read profiles without hitting profiles' own RLS.\n-- stable so Postgres can cache the result within a single transaction.\ncreate or replace function public.get_my_role()\nreturns text\nlanguage sql stable security definer\nset search_path = public\nas $$\n  select role from public.profiles where id = auth.uid()\n$$","-- ─── Helper: get current user's customer_id (for client portal access) ────────\ncreate or replace function public.get_my_customer_id()\nreturns text\nlanguage sql stable security definer\nset search_path = public\nas $$\n  select customer_id from public.profiles where id = auth.uid()\n$$","-- ─── Auth trigger: auto-create profiles row on new user signup ────────────────\n-- Role defaults to 'client'; pass raw_user_meta_data->>'role' to override at\n-- invitation time (e.g. when an admin creates a staff account via Supabase dashboard).\ncreate or replace function public.handle_new_user()\nreturns trigger\nlanguage plpgsql security definer\nset search_path = public\nas $$\nbegin\n  insert into public.profiles (id, full_name, avatar_url, role)\n  values (\n    new.id,\n    coalesce(new.raw_user_meta_data->>'full_name', new.raw_user_meta_data->>'name'),\n    new.raw_user_meta_data->>'avatar_url',\n    coalesce(new.raw_user_meta_data->>'role', 'client')\n  )\n  on conflict (id) do nothing;\n  return new;\nend;\n$$","drop trigger if exists on_auth_user_created on auth.users","create trigger on_auth_user_created\n  after insert on auth.users\n  for each row execute procedure public.handle_new_user()","-- ─── profiles ─────────────────────────────────────────────────────────────────\n-- Own row read (+ admin reads all).\ncreate policy \\"profiles_read_own\\"\n  on profiles for select to authenticated\n  using (auth.uid() = id or get_my_role() = 'admin')","-- Own row update — cannot change id or role via this policy.\ncreate policy \\"profiles_update_own\\"\n  on profiles for update to authenticated\n  using (auth.uid() = id)\n  with check (auth.uid() = id)","-- Admin full write (covers insert/update/delete across all rows).\ncreate policy \\"profiles_admin_write\\"\n  on profiles for all to authenticated\n  using (get_my_role() = 'admin')\n  with check (get_my_role() = 'admin')","-- ─── projects ─────────────────────────────────────────────────────────────────\n-- Migration 024 created a permissive policy for customer_projects (now projects).\n-- Drop it and replace with role-based policies.\ndrop policy if exists \\"Authenticated users can read customer_projects\\" on projects","-- Staff: all roles except client can read projects.\ncreate policy \\"projects_staff_read\\"\n  on projects for select to authenticated\n  using (get_my_role() in ('admin', 'pm', 'developer', 'hr'))","-- PM / Admin: full write.\ncreate policy \\"projects_pm_write\\"\n  on projects for all to authenticated\n  using (get_my_role() in ('admin', 'pm'))\n  with check (get_my_role() in ('admin', 'pm'))","-- ─── tasks ────────────────────────────────────────────────────────────────────\n-- Staff read (clients have no visibility into internal project tasks).\ncreate policy \\"tasks_staff_read\\"\n  on tasks for select to authenticated\n  using (get_my_role() in ('admin', 'pm', 'developer'))","-- PM / Admin: full write.\ncreate policy \\"tasks_pm_write\\"\n  on tasks for all to authenticated\n  using (get_my_role() in ('admin', 'pm'))\n  with check (get_my_role() in ('admin', 'pm'))","-- Developer: update tasks they are assigned to.\ncreate policy \\"tasks_developer_update\\"\n  on tasks for update to authenticated\n  using (get_my_role() = 'developer' and auth.uid() = any(assignees))\n  with check (get_my_role() = 'developer')","-- ─── task_comments ────────────────────────────────────────────────────────────\ncreate policy \\"task_comments_staff_read\\"\n  on task_comments for select to authenticated\n  using (get_my_role() in ('admin', 'pm', 'developer'))","create policy \\"task_comments_staff_insert\\"\n  on task_comments for insert to authenticated\n  with check (\n    get_my_role() in ('admin', 'pm', 'developer')\n    and author_id = auth.uid()\n  )","-- Own comment delete (+ admin).\ncreate policy \\"task_comments_delete\\"\n  on task_comments for delete to authenticated\n  using (get_my_role() = 'admin' or author_id = auth.uid())","-- ─── attachments ──────────────────────────────────────────────────────────────\ncreate policy \\"attachments_staff_read\\"\n  on attachments for select to authenticated\n  using (get_my_role() in ('admin', 'pm', 'developer'))","-- PM / Admin: full write.\ncreate policy \\"attachments_pm_write\\"\n  on attachments for all to authenticated\n  using (get_my_role() in ('admin', 'pm'))\n  with check (get_my_role() in ('admin', 'pm'))","-- Developer: insert own attachments only.\ncreate policy \\"attachments_developer_insert\\"\n  on attachments for insert to authenticated\n  with check (\n    get_my_role() = 'developer'\n    and uploaded_by = auth.uid()\n  )","-- ─── time_logs ────────────────────────────────────────────────────────────────\n-- PM / Admin / HR can read all (needed for timesheet oversight and digest).\ncreate policy \\"time_logs_manager_read\\"\n  on time_logs for select to authenticated\n  using (get_my_role() in ('admin', 'pm', 'hr'))","-- Developer: full CRUD on own rows only.\ncreate policy \\"time_logs_developer_own\\"\n  on time_logs for all to authenticated\n  using (get_my_role() = 'developer' and employee_id = auth.uid())\n  with check (get_my_role() = 'developer' and employee_id = auth.uid())","-- ─── tickets ──────────────────────────────────────────────────────────────────\n-- Staff: full access.\ncreate policy \\"tickets_staff_all\\"\n  on tickets for all to authenticated\n  using (get_my_role() in ('admin', 'pm', 'developer'))\n  with check (get_my_role() in ('admin', 'pm', 'developer'))","-- Client: read own tickets (by customer_id).\ncreate policy \\"tickets_client_read\\"\n  on tickets for select to authenticated\n  using (get_my_role() = 'client' and customer_id = get_my_customer_id())","-- Client: create tickets for their own customer.\ncreate policy \\"tickets_client_insert\\"\n  on tickets for insert to authenticated\n  with check (\n    get_my_role() = 'client'\n    and customer_id = get_my_customer_id()\n  )","-- ─── ticket_messages ──────────────────────────────────────────────────────────\n-- Staff: full access (can see internal + public messages).\ncreate policy \\"ticket_messages_staff_all\\"\n  on ticket_messages for all to authenticated\n  using (get_my_role() in ('admin', 'pm', 'developer'))\n  with check (get_my_role() in ('admin', 'pm', 'developer'))","-- Client: read public messages on own customer's tickets.\ncreate policy \\"ticket_messages_client_read\\"\n  on ticket_messages for select to authenticated\n  using (\n    get_my_role() = 'client'\n    and visibility = 'public'\n    and ticket_id in (\n      select id from tickets where customer_id = get_my_customer_id()\n    )\n  )","-- Client: send public messages on own customer's tickets.\ncreate policy \\"ticket_messages_client_insert\\"\n  on ticket_messages for insert to authenticated\n  with check (\n    get_my_role() = 'client'\n    and visibility = 'public'\n    and ticket_id in (\n      select id from tickets where customer_id = get_my_customer_id()\n    )\n  )","-- ─── event_bus ────────────────────────────────────────────────────────────────\n-- Internal plumbing: staff can insert events; admin can read/manage.\ncreate policy \\"event_bus_staff_insert\\"\n  on event_bus for insert to authenticated\n  with check (get_my_role() in ('admin', 'pm', 'developer'))","create policy \\"event_bus_admin_read\\"\n  on event_bus for select to authenticated\n  using (get_my_role() = 'admin')","-- ─── notifications ────────────────────────────────────────────────────────────\n-- Each user sees and manages only their own notifications.\ncreate policy \\"notifications_own\\"\n  on notifications for all to authenticated\n  using (recipient_id = auth.uid())\n  with check (recipient_id = auth.uid())","-- ─── notification_preferences ─────────────────────────────────────────────────\ncreate policy \\"notification_preferences_own\\"\n  on notification_preferences for all to authenticated\n  using (profile_id = auth.uid())\n  with check (profile_id = auth.uid())","-- ─── push_subscriptions ───────────────────────────────────────────────────────\ncreate policy \\"push_subscriptions_own\\"\n  on push_subscriptions for all to authenticated\n  using (profile_id = auth.uid())\n  with check (profile_id = auth.uid())","-- ─── audit_logs ───────────────────────────────────────────────────────────────\n-- Written by service role / triggers only. Admins can read; no one else can.\ncreate policy \\"audit_logs_admin_read\\"\n  on audit_logs for select to authenticated\n  using (get_my_role() = 'admin')","-- ─── hr.employees ─────────────────────────────────────────────────────────────\n-- HR / Admin: full CRUD.\ncreate policy \\"hr_employees_hr_admin_all\\"\n  on hr.employees for all to authenticated\n  using (get_my_role() in ('admin', 'hr'))\n  with check (get_my_role() in ('admin', 'hr'))","-- PM: read all employee records (needed for assignment and oversight).\ncreate policy \\"hr_employees_pm_read\\"\n  on hr.employees for select to authenticated\n  using (get_my_role() = 'pm')","-- Developer: read own employee record.\ncreate policy \\"hr_employees_developer_own\\"\n  on hr.employees for select to authenticated\n  using (get_my_role() = 'developer' and profile_id = auth.uid())","-- ─── hr.attendance_punches ────────────────────────────────────────────────────\ncreate policy \\"hr_attendance_punches_hr_admin\\"\n  on hr.attendance_punches for all to authenticated\n  using (get_my_role() in ('admin', 'hr'))\n  with check (get_my_role() in ('admin', 'hr'))","-- Developer: own punches (clock in/out).\ncreate policy \\"hr_attendance_punches_developer_own\\"\n  on hr.attendance_punches for all to authenticated\n  using (\n    get_my_role() = 'developer'\n    and employee_id in (select id from hr.employees where profile_id = auth.uid())\n  )\n  with check (\n    get_my_role() = 'developer'\n    and employee_id in (select id from hr.employees where profile_id = auth.uid())\n  )","-- ─── hr.attendance_days ───────────────────────────────────────────────────────\ncreate policy \\"hr_attendance_days_hr_admin\\"\n  on hr.attendance_days for all to authenticated\n  using (get_my_role() in ('admin', 'hr'))\n  with check (get_my_role() in ('admin', 'hr'))","-- PM: read (leave calendar visibility).\ncreate policy \\"hr_attendance_days_pm_read\\"\n  on hr.attendance_days for select to authenticated\n  using (get_my_role() = 'pm')","-- Developer: read own attendance days.\ncreate policy \\"hr_attendance_days_developer_own\\"\n  on hr.attendance_days for select to authenticated\n  using (\n    get_my_role() = 'developer'\n    and employee_id in (select id from hr.employees where profile_id = auth.uid())\n  )","-- ─── hr.leave_types ───────────────────────────────────────────────────────────\n-- Lookup table: all authenticated staff can read; HR/admin write.\ncreate policy \\"hr_leave_types_staff_read\\"\n  on hr.leave_types for select to authenticated\n  using (get_my_role() in ('admin', 'hr', 'pm', 'developer'))","create policy \\"hr_leave_types_hr_admin_write\\"\n  on hr.leave_types for all to authenticated\n  using (get_my_role() in ('admin', 'hr'))\n  with check (get_my_role() in ('admin', 'hr'))","-- ─── hr.leave_balances ────────────────────────────────────────────────────────\ncreate policy \\"hr_leave_balances_hr_admin\\"\n  on hr.leave_balances for all to authenticated\n  using (get_my_role() in ('admin', 'hr'))\n  with check (get_my_role() in ('admin', 'hr'))","-- Developer: read own balances.\ncreate policy \\"hr_leave_balances_developer_own\\"\n  on hr.leave_balances for select to authenticated\n  using (\n    get_my_role() = 'developer'\n    and employee_id in (select id from hr.employees where profile_id = auth.uid())\n  )","-- ─── hr.leave_requests ────────────────────────────────────────────────────────\ncreate policy \\"hr_leave_requests_hr_admin\\"\n  on hr.leave_requests for all to authenticated\n  using (get_my_role() in ('admin', 'hr'))\n  with check (get_my_role() in ('admin', 'hr'))","-- PM: read (for leave calendar).\ncreate policy \\"hr_leave_requests_pm_read\\"\n  on hr.leave_requests for select to authenticated\n  using (get_my_role() = 'pm')","-- Developer: CRUD own leave requests.\ncreate policy \\"hr_leave_requests_developer_own\\"\n  on hr.leave_requests for all to authenticated\n  using (\n    get_my_role() = 'developer'\n    and employee_id in (select id from hr.employees where profile_id = auth.uid())\n  )\n  with check (\n    get_my_role() = 'developer'\n    and employee_id in (select id from hr.employees where profile_id = auth.uid())\n  )","-- ─── hr.timesheets ────────────────────────────────────────────────────────────\ncreate policy \\"hr_timesheets_hr_admin\\"\n  on hr.timesheets for all to authenticated\n  using (get_my_role() in ('admin', 'hr'))\n  with check (get_my_role() in ('admin', 'hr'))","-- PM: read (for oversight).\ncreate policy \\"hr_timesheets_pm_read\\"\n  on hr.timesheets for select to authenticated\n  using (get_my_role() = 'pm')","-- Developer: own timesheets.\ncreate policy \\"hr_timesheets_developer_own\\"\n  on hr.timesheets for all to authenticated\n  using (\n    get_my_role() = 'developer'\n    and employee_id in (select id from hr.employees where profile_id = auth.uid())\n  )\n  with check (\n    get_my_role() = 'developer'\n    and employee_id in (select id from hr.employees where profile_id = auth.uid())\n  )","-- ─── hr.announcements ─────────────────────────────────────────────────────────\n-- All staff can read; HR/admin write.\ncreate policy \\"hr_announcements_staff_read\\"\n  on hr.announcements for select to authenticated\n  using (get_my_role() in ('admin', 'hr', 'pm', 'developer'))","create policy \\"hr_announcements_hr_admin_write\\"\n  on hr.announcements for all to authenticated\n  using (get_my_role() in ('admin', 'hr'))\n  with check (get_my_role() in ('admin', 'hr'))","-- ─── hr.hr_requests ───────────────────────────────────────────────────────────\ncreate policy \\"hr_requests_hr_admin\\"\n  on hr.hr_requests for all to authenticated\n  using (get_my_role() in ('admin', 'hr'))\n  with check (get_my_role() in ('admin', 'hr'))","-- Developer: CRUD own HR requests.\ncreate policy \\"hr_requests_developer_own\\"\n  on hr.hr_requests for all to authenticated\n  using (\n    get_my_role() = 'developer'\n    and employee_id in (select id from hr.employees where profile_id = auth.uid())\n  )\n  with check (\n    get_my_role() = 'developer'\n    and employee_id in (select id from hr.employees where profile_id = auth.uid())\n  )"}	rls_policies_v2
027	{"-- Migration 027: Knowledge Base schema\n-- Adds pgvector extension, kb_entries, task_logs, kb_corrections, and match_kb_entries function\n-- Prerequisites: T063 — required by T067 (Orchestrator) and T068 (KB Library)\n\n-- Enable pgvector extension (idempotent — safe if already enabled)\ncreate extension if not exists vector","-- KB entries: stores vector-indexed execution patterns for semantic reuse\ncreate table if not exists kb_entries (\n  id uuid primary key default gen_random_uuid(),\n  request_pattern text,\n  embedding vector(1536),\n  classification text check (classification in ('sanity', 'code', 'both')),\n  lane int check (lane in (1, 2, 3)),\n  tools_used text[],\n  execution_steps jsonb,\n  outcome text check (outcome in ('success', 'failed', 'overridden')),\n  project_id text,\n  use_count int default 1,\n  flagged bool default false,\n  created_at timestamptz default now(),\n  last_used_at timestamptz default now()\n)","-- Cosine similarity search over kb_entries embeddings\ncreate or replace function match_kb_entries(\n  query_embedding vector(1536),\n  match_threshold float,\n  match_count int\n)\nreturns table(\n  id uuid,\n  request_pattern text,\n  classification text,\n  lane int,\n  execution_steps jsonb,\n  similarity float\n)\nlanguage sql stable as $$\n  select\n    id,\n    request_pattern,\n    classification,\n    lane,\n    execution_steps,\n    1 - (embedding <=> query_embedding) as similarity\n  from kb_entries\n  where 1 - (embedding <=> query_embedding) > match_threshold\n  order by similarity desc\n  limit match_count;\n$$","-- Audit log: every pipeline execution is logged with the triggering Central Hub user\ncreate table if not exists task_logs (\n  id uuid primary key default gen_random_uuid(),\n  task_id text,\n  project_id text,\n  description text,\n  lane int,\n  tools_called text[],\n  result text,\n  kb_hit bool,\n  triggered_by text,       -- Central Hub user email (not the Sanity robot account)\n  triggered_by_id text,    -- Central Hub user UUID\n  created_at timestamptz default now()\n)","-- Human corrections: when a PM/dev overrides Claude's lane, the correction is recorded\n-- and kb_entries.flagged is set to true for the affected entry\ncreate table if not exists kb_corrections (\n  id uuid primary key default gen_random_uuid(),\n  kb_entry_id uuid references kb_entries(id) on delete cascade,\n  original_lane int,\n  corrected_lane int,\n  corrected_by text,\n  reason text,\n  corrected_at timestamptz default now()\n)"}	kb_schema
028	{"alter table projects\n  add column if not exists dataset text,\n  add column if not exists vercel_project_id text"}	projects_vercel_dataset
029	{"alter table classification_records\n  add column if not exists sub_tasks jsonb"}	classification_subtasks
030	{"create extension if not exists pg_trgm","-- Text-similarity KB lookup — no embedding/OpenAI required.\n-- Uses pg_trgm similarity() on request_pattern; threshold typically 0.2–0.4.\ncreate or replace function match_kb_by_text(\n  query_text text,\n  match_threshold float default 0.2,\n  match_count int default 1\n)\nreturns table (\n  id text,\n  request_pattern text,\n  classification text,\n  lane int,\n  execution_steps jsonb,\n  similarity float\n)\nlanguage sql stable\nas $$\n  select * from (\n    select\n      e.id::text,\n      e.request_pattern,\n      e.classification,\n      e.lane,\n      e.execution_steps::jsonb,\n      similarity(e.request_pattern, query_text) as similarity\n    from kb_entries e\n    where e.request_pattern is not null\n  ) sub\n  where sub.similarity > match_threshold\n  order by sub.similarity desc\n  limit match_count;\n$$"}	pg_trgm_kb
031	{"alter table execution_records\n  add column if not exists health_check_status text,\n  add column if not exists health_check_url text"}	execution_health_check
032	{"-- Migration 030: Add ops_chat orchestration layer\n-- Widens CHECK constraints on llm_config and llm_invocation_logs, then seeds the config row.\n-- ⚠️ Verify constraint names match your live DB before applying:\n--    \\\\d+ llm_config          → look for *_orchestration_layer_check\n--    \\\\d+ llm_invocation_logs → look for *_orchestration_layer_check\n\n-- ─── llm_config ───────────────────────────────────────────────────────────────\nalter table llm_config\n  drop constraint if exists llm_config_orchestration_layer_check","alter table llm_config\n  add constraint llm_config_orchestration_layer_check\n    check (orchestration_layer in (\n      'classification','assessment','planning','execution',\n      'digest','reply','wiki_lint','ops_chat'\n    ))","-- ─── llm_invocation_logs ──────────────────────────────────────────────────────\nalter table llm_invocation_logs\n  drop constraint if exists llm_invocation_logs_orchestration_layer_check","alter table llm_invocation_logs\n  add constraint llm_invocation_logs_orchestration_layer_check\n    check (orchestration_layer in (\n      'classification','assessment','planning','execution',\n      'digest','reply','wiki_lint','ops_chat'\n    ))","-- ─── Seed ops_chat model row ──────────────────────────────────────────────────\ninsert into llm_config (orchestration_layer, model_id, max_tokens, temperature, notes)\nvalues (\n  'ops_chat',\n  'claude-sonnet-4-6',\n  8192,\n  0.30,\n  'Sonnet: streaming Ops Chat agent — task/ticket reads + Sanity MCP automation; DRAFT-only writes'\n)\non conflict (orchestration_layer) do update set\n  model_id    = excluded.model_id,\n  max_tokens  = excluded.max_tokens,\n  temperature = excluded.temperature,\n  notes       = excluded.notes,\n  updated_at  = now()"}	ops_chat_llm_layer
033	{"-- Migration 033: milestones (PM core) + tasks.milestone_id\n-- Adds milestone grouping under projects for the native PM core (task 073).\n-- RLS mirrors tasks/projects: staff read; PM/Admin full write. Uses get_my_role()\n-- helper (migration 026) — never replicate the role lookup inline.\n\n-- ─── milestones ───────────────────────────────────────────────────────────────\ncreate table milestones (\n  id uuid primary key default gen_random_uuid(),\n  project_id uuid not null references projects(id) on delete cascade,\n  name text not null,\n  description text,\n  due_date date,\n  status text not null check (status in ('planned', 'active', 'completed')) default 'planned',\n  position numeric,\n  created_by uuid references auth.users(id) on delete set null,\n  created_at timestamptz not null default now(),\n  updated_at timestamptz not null default now()\n)","-- ─── tasks.milestone_id ───────────────────────────────────────────────────────\nalter table tasks\n  add column milestone_id uuid references milestones(id) on delete set null","-- ─── RLS ──────────────────────────────────────────────────────────────────────\nalter table milestones enable row level security","-- Staff read (clients have no visibility into internal project milestones).\ncreate policy \\"milestones_staff_read\\"\n  on milestones for select to authenticated\n  using (get_my_role() in ('admin', 'pm', 'developer'))","-- PM / Admin: full write.\ncreate policy \\"milestones_pm_write\\"\n  on milestones for all to authenticated\n  using (get_my_role() in ('admin', 'pm'))\n  with check (get_my_role() in ('admin', 'pm'))","-- ─── Indexes ──────────────────────────────────────────────────────────────────\ncreate index milestones_project_id_idx on milestones(project_id)","create index tasks_milestone_id_idx on tasks(milestone_id)"}	milestones
034	{"-- 034_zoho_task_statuses.sql\n-- Align tasks.status with Zoho Projects workflow.\n-- New values: open | in_progress | ready_for_qa | testing_completed |\n--             for_client_approval | ready_to_merge | post_live_qa | closed\n\n-- Step 1: Drop old constraint first so the remapping UPDATEs are not rejected\nALTER TABLE tasks DROP CONSTRAINT IF EXISTS tasks_status_check","-- Step 2: Remap existing rows to new status values\nUPDATE tasks SET status = 'open'         WHERE status IN ('backlog', 'todo')","UPDATE tasks SET status = 'ready_for_qa' WHERE status = 'for_review'","UPDATE tasks SET status = 'closed'       WHERE status IN ('done', 'cancelled')","-- Step 3: Add new constraint\nALTER TABLE tasks\n  ADD CONSTRAINT tasks_status_check\n  CHECK (status IN (\n    'open',\n    'in_progress',\n    'ready_for_qa',\n    'testing_completed',\n    'for_client_approval',\n    'ready_to_merge',\n    'post_live_qa',\n    'closed'\n  ))","-- Step 4: Update column default\nALTER TABLE tasks ALTER COLUMN status SET DEFAULT 'open'"}	zoho_task_statuses
035	{"-- Migration 035: Zoho Decommission Schema\n-- Adds tables and columns needed for the one-time Zoho → Supabase migration.\n--\n-- Design principles:\n--   external_id  text unique — the import dedup key per table; null for Hub-native rows\n--   source_meta  jsonb       — single blob for Zoho-specific data that has no long-term\n--                              Hub equivalent (status names, zpuids, timestamps, tags).\n--                              Drop this column once the migration is verified complete.\n--   First-class columns      — data with genuine ongoing value (dates, website URLs,\n--                              owner display names) get proper named columns.\n--\n-- Import order: projects → tasklists → tasks → comments → timelogs → attachments.\n-- Uses get_my_role() (migration 026) for RLS — never replicate inline.\n\n-- ─── tasklists ────────────────────────────────────────────────────────────────\ncreate table tasklists (\n  id uuid primary key default gen_random_uuid(),\n  project_id uuid not null references projects(id) on delete cascade,\n  external_id text unique,   -- source system ID (Zoho tasklist ID); null for Hub-native\n  name text not null,\n  position numeric,\n  is_default boolean default false,\n  created_at timestamptz not null default now(),\n  updated_at timestamptz not null default now()\n)","alter table tasklists enable row level security","create policy \\"tasklists_staff_read\\"\n  on tasklists for select to authenticated\n  using (get_my_role() in ('admin', 'pm', 'developer'))","create policy \\"tasklists_pm_write\\"\n  on tasklists for all to authenticated\n  using (get_my_role() in ('admin', 'pm'))\n  with check (get_my_role() in ('admin', 'pm'))","create index tasklists_project_id_idx on tasklists(project_id)","-- ─── tasks: migration columns ──────────────────────────────────────────────────\nalter table tasks\n  add column tasklist_id uuid references tasklists(id) on delete set null,\n  add column external_id text unique,   -- source system ID; null for Hub-native tasks\n  add column start_date date","create index tasks_external_id_idx on tasks(external_id) where external_id is not null","create index tasks_tasklist_id_idx on tasks(tasklist_id)","-- Allow null task_id on time_logs: Zoho project-level time entries have no task reference\nalter table time_logs alter column task_id drop not null","-- ─── projects: first-class data + one source_meta blob ────────────────────────\n-- First-class: real project data that belongs in the schema regardless of source\nalter table projects\n  add column start_date date,\n  add column end_date date,\n  add column percent_complete integer default 0,\n  add column existing_website text,        -- client's current site (Zoho custom field)\n  add column development_site text","-- WebriQ staging/dev URL (Zoho custom field)\n\n-- source_meta: Zoho-specific operational data kept for reference during transition.\n-- Contents: {status_name, status_id, is_closed, owner_zpuid, owner_email,\n--            project_group, tags, modified_at, completed_at, synced_at}\n-- Safe to drop this column after migration is fully verified.\nalter table projects\n  add column source_meta jsonb default '{}'","-- ─── task_comments: support imported comments with no Hub user account ─────────\n-- Zoho commenters may not have Hub accounts — author_id becomes nullable.\n-- FK changes from ON DELETE CASCADE → ON DELETE SET NULL to preserve imported history\n-- when a Hub user account is later deleted.\nalter table task_comments alter column author_id drop not null","alter table task_comments drop constraint task_comments_author_id_fkey","alter table task_comments\n  add constraint task_comments_author_id_fkey\n    foreign key (author_id) references auth.users(id) on delete set null","alter table task_comments\n  add column external_id text unique,   -- source system comment ID\n  add column author_name text,          -- display name when author has no Hub account\n  add column author_email text","-- email when author has no Hub account\n\n-- ─── attachments: migration columns ───────────────────────────────────────────\nalter table attachments\n  add column external_id text unique,   -- source system attachment ID\n  add column source_url text","-- original CDN URL; fallback if storage upload failed\n\n-- ─── time_logs: migration columns ─────────────────────────────────────────────\nalter table time_logs\n  add column external_id text unique,   -- source system timelog ID\n  add column owner_name text,           -- display name when logger has no Hub account\n  add column owner_email text","-- email when logger has no Hub account"}	zoho_decommission_schema
036	{"-- Migration 036: Project listing performance + first-class tags/owner columns\n--\n-- Adds indexes needed before server-side pagination is meaningful.\n-- Adds tags text[] and owner_name text as first-class columns on projects.\n-- owner_name stores the Zoho owner display name for rows imported from Zoho\n-- (created_by is always null for imported rows so profiles join is not possible).\n\n-- ─── Indexes ──────────────────────────────────────────────────────────────────\nCREATE INDEX IF NOT EXISTS idx_projects_status   ON projects(status)","CREATE INDEX IF NOT EXISTS idx_projects_customer ON projects(customer_id)","CREATE INDEX IF NOT EXISTS idx_projects_updated  ON projects(updated_at DESC)","CREATE INDEX IF NOT EXISTS idx_tasks_project     ON tasks(project_id)","CREATE INDEX IF NOT EXISTS idx_tasks_status      ON tasks(status)","-- ─── First-class columns ──────────────────────────────────────────────────────\n-- tags: extracted from Zoho tags[].name; also editable in the Hub create/edit modal\nALTER TABLE projects ADD COLUMN IF NOT EXISTS tags text[] DEFAULT '{}'","-- owner_name: Zoho owner.full_name (PM display name). Null for Hub-native rows\n-- where created_by already links to a profiles row.\nALTER TABLE projects ADD COLUMN IF NOT EXISTS owner_name text"}	projects_indexes_tags
037	{"-- Migration 037: milestones migration columns\n-- Adds external_id to milestones for Zoho dedup during one-time import.\n-- Adds milestone_id to tasklists to preserve the Zoho hierarchy:\n--   project → milestone → tasklist → task.\n-- Safe to drop external_id after migration is fully verified.\n\nalter table milestones\n  add column external_id text unique","create index milestones_external_id_idx on milestones(external_id) where external_id is not null","alter table tasklists\n  add column milestone_id uuid references milestones(id) on delete set null","create index tasklists_milestone_id_idx on tasklists(milestone_id)"}	milestones_migration_columns
038	{"-- Migration 038: add start_date to milestones\n-- Zoho exports start_date on every milestone; captured here for import fidelity.\nalter table milestones\n  add column start_date date"}	milestones_start_date
